import React, { useState } from 'react';
import axios from 'axios';
import './App.css';

// Настраиваем axios для работы с сессиями Flask-Login
const api = axios.create({
  baseURL: 'http://localhost:5000',
  // withCredentials: true,
});

function App() {
  const [form, setForm] = useState({ login: '', password: '' });
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [loading, setLoading] = useState(false);
  const [message, setMessage] = useState('');
  const [messageType, setMessageType] = useState(''); // 'success' или 'error'

  const showMessage = (text, type) => {
    setMessage(text);
    setMessageType(type);
    // Автоматически скрываем сообщение через 5 секунд
    setTimeout(() => {
      setMessage('');
      setMessageType('');
    }, 5000);
  };

  // Обработчик входа
  const handleLogin = async (e) => {
    e.preventDefault();
    setLoading(true);
    setMessage('');
    setMessageType('');

    try {
      const response = await api.post('/login', form);

      if (response.status === 200) {
        setIsLoggedIn(true);
        showMessage(`✅ ${response.data.message}`, 'success');
        setForm({ login: '', password: '' });
      }
    } catch (error) {
      if (error.response) {
        showMessage(`❌ ${error.response.data.message}`, 'error');
      } else {
        showMessage('❌ Ошибка соединения с сервером', 'error');
      }
      setIsLoggedIn(false);
    } finally {
      setLoading(false);
    }
  };

  // Обработчик выхода
  const handleLogout = async () => {
    setLoading(true);
    setMessage('');
    setMessageType('');

    try {
      const response = await api.post('/logout');

      if (response.status === 200) {
        setIsLoggedIn(false);
        showMessage(`✅ ${response.data.message}`, 'success');
      }
    } catch (error) {
      showMessage('❌ Ошибка при выходе', 'error');
    } finally {
      setLoading(false);
    }
  };

  // Обработчик изменения полей формы
  const handleInputChange = (e) => {
    const { name, value } = e.target;
    setForm(prev => ({
      ...prev,
      [name]: value
    }));
  };

  // Если пользователь авторизован
  if (isLoggedIn) {
    return (
      <div className="app-container">
        <div className="app-card">
          <h2 className="app-title">Вы успешно авторизованы!</h2>
          <p className="app-subtitle">Сессия активна</p>

          <div className="user-info">
            <p><strong>Логин:</strong> {form.login || 'Пользователь'}</p>
            <p>Используйте браузерные инструменты разработчика, чтобы увидеть сессионную куку</p>
          </div>

          <button 
            onClick={handleLogout} 
            className="logout-button"
            disabled={loading}
          >
            {loading ? (
              <>
                <span className="spinner"></span>
                Выход...
              </>
            ) : 'Выйти'}
          </button>

          {message && (
            <div className={`message ${messageType}-message`}>
              {message}
            </div>
          )}
        </div>
      </div>
    );
  }

  // Форма входа
  return (
    <div className="app-container">
      <div className="app-card">
        <h2 className="app-title">Вход в систему</h2>
        <p className="app-subtitle">Введите логин и пароль</p>

        {message && (
          <div className={`message ${messageType}-message`}>
            {message}
          </div>
        )}

        <form onSubmit={handleLogin} className="app-form">
          <div className="form-group">
            <input
              type="text"
              name="login"
              value={form.login}
              onChange={handleInputChange}
              className="form-input"
              placeholder="Логин"
              required
              disabled={loading}
              autoComplete="username"
            />
          </div>

          <div className="form-group">
            <input
              type="password"
              name="password"
              value={form.password}
              onChange={handleInputChange}
              className="form-input"
              placeholder="Пароль"
              required
              disabled={loading}
              autoComplete="current-password"
            />
          </div>

          <button 
            type="submit" 
            className="login-button"
            disabled={loading || !form.login || !form.password}
          >
            {loading ? (
              <>
                <span className="spinner"></span>
                Вход...
              </>
            ) : 'Войти'}
          </button>
        </form>
      </div>
    </div>
  );
}

export default App;
